import { Button, Field, FieldEditor, Inline, Panel, Stack, useField, useFields, useUpdateField, useViewState } from '@netior/interactive-sdk';

export function View() {
  const fields = useFields();
  const updateField = useUpdateField();
  const firstFieldId = fields[0]?.field?.id ?? null;
  const [selectedFieldId, setSelectedFieldId] = useViewState('selectedFieldId', firstFieldId);
  const selected = fields.find((item) => item.field?.id === selectedFieldId) ?? fields[0] ?? null;
  const [draft, setDraft] = useViewState('draft', selected?.value ?? '');
  const [saveCount, setSaveCount] = useViewState('saveCount', 0);

  if (fields.length === 0) {
    return (
      <Panel>
        <div className="text-sm text-muted">This instance has no schema fields.</div>
      </Panel>
    );
  }

  const selectedKey = selected?.field?.id ?? '';

  return (
    <Stack>
      <Panel>
        <Stack>
          <div className="text-sm font-medium text-default">Field Review Demo</div>
          <Inline>
            {fields.map(({ field }) => field ? (
              <Button
                key={field.id}
                variant={field.id === selectedKey ? 'primary' : 'secondary'}
                onClick={() => {
                  setSelectedFieldId(field.id);
                  const next = fields.find((item) => item.field?.id === field.id);
                  setDraft(next?.value ?? '');
                }}
              >
                {field.name}
              </Button>
            ) : null)}
          </Inline>
        </Stack>
      </Panel>

      {selected?.field ? (
        <Panel>
          <Stack>
            <Field name={selected.field.id} />
            <FieldEditor
              fieldKey={selected.field.id}
              draft={draft ?? ''}
              onDraftChange={setDraft}
              onSave={() => {
                updateField(selected.field.id, draft ?? '');
                setSaveCount(saveCount + 1);
              }}
            />
            <div className="text-xs text-muted">Saved from this view: {saveCount}</div>
          </Stack>
        </Panel>
      ) : null}
    </Stack>
  );
}
